document.addEventListener("DOMContentLoaded",(()=>{const e=" ".repeat(12);document.getElementById("selectedUser").innerHTML="Χρήστης : Group : ",(async()=>{try{const t=await fetch("/api/user"),n=await t.json();if(n){let t=n.firstName,r=t.length>12?t.substring(0,12):t+e.substring(0,12-t.length);document.getElementById("selectedUser").innerHTML="Χρήστης: "+r+" ➜ Group: "+n.team}}catch(e){console.error("Πρόβλημα κατά την εμφάνιση του ονόματος και της ομάδας εργασίας του χρήστη:",e)}})()}));